/*!40101 SET NAMES binary*/;
/*!40014 SET FOREIGN_KEY_CHECKS=0*/;
/*!40101 SET SQL_MODE='NO_AUTO_VALUE_ON_ZERO,NO_ENGINE_SUBSTITUTION'*/;
/*!40103 SET TIME_ZONE='+00:00' */;
DROP TABLE IF EXISTS `view_agents`;
DROP VIEW IF EXISTS `view_agents`;
SET @PREV_CHARACTER_SET_CLIENT=@@CHARACTER_SET_CLIENT;
SET @PREV_CHARACTER_SET_RESULTS=@@CHARACTER_SET_RESULTS;
SET @PREV_COLLATION_CONNECTION=@@COLLATION_CONNECTION;
SET character_set_client = utf8mb4;
SET character_set_results = utf8mb4;
SET collation_connection = utf8mb4_general_ci;
CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`%` SQL SECURITY DEFINER VIEW `view_agents` AS select `KYDB_NEW`.`agent`.`id` AS `agent`,`KYDB_NEW`.`agent`.`id` AS `channelId`,`KYDB_NEW`.`agent`.`uid` AS `parent`,`KYDB_NEW`.`agent`.`account` AS `accounts`,`KYDB_NEW`.`agent`.`nickname` AS `nickName`,`KYDB_NEW`.`agent`.`moneyType` AS `moneytype`,`KYDB_NEW`.`agent`.`createUser` AS `createUser`,`KYDB_NEW`.`agent`.`accountingFor` AS `accountingFor`,0 AS `sportAccountingFor`,`KYDB_NEW`.`agent`.`lastLoginTime` AS `lastLoginTime`,`KYDB_NEW`.`agent`.`cooperation` AS `cooperation`,`KYDB_NEW`.`agent`.`businessAccount` AS `businessAccount`,`KYDB_NEW`.`agent`.`type` AS `singleOrSystem`,`KYDB_NEW`.`agent`.`userStatus` AS `userStatus`,`wallet`.`money` AS `money`,`KYDB_NEW`.`agent`.`whiteIp` AS `whiteip`,`KYDB_NEW`.`agent`.`status` AS `status`,`KYDB_NEW`.`agent`.`proxyUrl` AS `proxyurl`,`KYDB_NEW`.`agent`.`aesKey` AS `desKey`,`KYDB_NEW`.`agent`.`md5Key` AS `md5Key`,`KYDB_NEW`.`agent`.`callBackType` AS `callbackurl`,`lineCode`.`lineCode` AS `lineCodes`,`KYDB_NEW`.`agent`.`exRate` AS `exRate`,`KYDB_NEW`.`agent`.`publicId` AS `publicId`,`KYDB_NEW`.`agent`.`revenue` AS `pumping`,`KYDB_NEW`.`agent`.`isShowBackLobby` AS `backmain`,`KYDB_NEW`.`agent`.`offlineBackUrl` AS `oflinebackurl`,`KYDB_NEW`.`agent`.`isShowFeedback` AS `feedEnabled`,`KYDB_NEW`.`agent`.`logoUrl` AS `logoUrl`,(case `KYDB_NEW`.`agent`.`timeZone` when 0 then 8 when 1 then -(4) else 0 end) AS `timeZone`,`KYDB_NEW`.`agent`.`isShowPayPopUps` AS `isPayPopUps`,`KYDB_NEW`.`agent`.`payType` AS `isAutoPay`,`KYDB_NEW`.`agent`.`walletType` AS `walletType`,0 AS `sboStatus`,`KYDB_NEW`.`agent`.`createDate` AS `createdate`,`KYDB_NEW`.`agent`.`rechargeUrl` AS `rechargeUrl`,`KYDB_NEW`.`agent`.`rechargeStatus` AS `rechargeStatus`,`KYDB_NEW`.`agent`.`sbUrl` AS `sbUrl`,`KYDB_NEW`.`agent`.`convertMultiple` AS `convertMultiple`,`KYDB_NEW`.`agent`.`lang` AS `lang`,`KYDB_NEW`.`agent`.`theme` AS `theme`,`KYDB_NEW`.`agent`.`autoMatch` AS `autoMatch`,`KYDB_NEW`.`agent`.`gameFrameControl` AS `gameFrameControl`,`KYDB_NEW`.`agent`.`gameFrameTeachControl` AS `gameFrameTeachControl`,`KYDB_NEW`.`agent`.`gameFullScreenControl` AS `gameFullScreenControl`,`KYDB_NEW`.`agent`.`gameMusicControl` AS `gameMusicControl` from ((`KYDB_NEW`.`agent` join `wallet`.`agents` `wallet` on((`KYDB_NEW`.`agent`.`id` = `wallet`.`channelId`))) left join (select `KYDB_NEW`.`sys_agent_linecode`.`agentId` AS `agentId`,concat('[',group_concat(concat('"',`KYDB_NEW`.`sys_agent_linecode`.`linecode`,'"') separator ','),']') AS `lineCode` from `KYDB_NEW`.`sys_agent_linecode` group by `KYDB_NEW`.`sys_agent_linecode`.`agentId`) `lineCode` on((`KYDB_NEW`.`agent`.`id` = `lineCode`.`agentId`)));
SET character_set_client = @PREV_CHARACTER_SET_CLIENT;
SET character_set_results = @PREV_CHARACTER_SET_RESULTS;
SET collation_connection = @PREV_COLLATION_CONNECTION;
